import { create } from 'zustand'

export const useGameStore = create((set) => ({
  // 현재 씬
  currentScene: 'simple', // simple, banner, opening1, opening2, opening3, opening4

  // 게임 데이터
  playerName: '',
  selectedEgg: null,
  babyCarName: '',

  // 액션
  setScene: (scene) => set({ currentScene: scene }),
  setPlayerName: (name) => set({ playerName: name }),
  setSelectedEgg: (egg) => set({ selectedEgg: egg }),
  setBabyCarName: (name) => set({ babyCarName: name }),
}))
