import { useGameStore } from './store'
import TestScene from './TestScene'
import SimpleBanner from './scenes/SimpleBanner'
import './styles.css'

// 3D 씬들 - 에러 발생 시 대비
let BannerScene, Opening1Scene, Opening2Scene
try {
  BannerScene = require('./scenes/BannerScene').default
  Opening1Scene = require('./scenes/Opening1Scene').default
  Opening2Scene = require('./scenes/Opening2Scene').default
} catch (error) {
  console.error('3D Scenes loading error:', error)
}

function App() {
  const currentScene = useGameStore((state) => state.currentScene)

  // 에러 체크
  if (!BannerScene) {
    return (
      <div style={{
        width: '100vw',
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: '#f44336',
        color: 'white',
        fontSize: '20px',
        padding: '20px',
        textAlign: 'center'
      }}>
        <div>
          <h1>⚠️ 로딩 에러</h1>
          <p>3D 씬을 로드할 수 없습니다.</p>
          <p style={{ fontSize: '14px', marginTop: '20px' }}>
            브라우저 콘솔(F12)을 확인하세요.
          </p>
        </div>
      </div>
    )
  }

  const renderScene = () => {
    try {
      switch (currentScene) {
        case 'test':
          return <TestScene />
        case 'simple':
          return <SimpleBanner />
        case 'banner':
          return BannerScene ? <BannerScene /> : <SimpleBanner />
        case 'opening1':
          return Opening1Scene ? <Opening1Scene /> : <SimpleBanner />
        case 'opening2':
          return Opening2Scene ? <Opening2Scene /> : <SimpleBanner />
        default:
          return <SimpleBanner />
      }
    } catch (error) {
      console.error('Scene render error:', error)
      return (
        <div style={{
          width: '100vw',
          height: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          background: '#ff9800',
          color: 'white',
          fontSize: '20px',
          padding: '20px',
          textAlign: 'center'
        }}>
          <div>
            <h1>🐛 렌더링 에러</h1>
            <p>{error.message}</p>
            <button
              onClick={() => window.location.reload()}
              style={{
                marginTop: '20px',
                padding: '10px 20px',
                fontSize: '16px',
                background: 'white',
                color: '#ff9800',
                border: 'none',
                borderRadius: '5px',
                cursor: 'pointer'
              }}
            >
              새로고침
            </button>
          </div>
        </div>
      )
    }
  }

  return (
    <div style={{ width: '100vw', height: '100vh', overflow: 'hidden' }}>
      {renderScene()}
    </div>
  )
}

export default App
